(function(w){'use strict';if(w.Dropzone)return;function Dropzone(el,opts){this.element=el;this.options=opts||{};this.handlers={};this.files=[];el.dropzone=this;}Dropzone.autoDiscover=false;Dropzone.prototype.on=function(n,cb){(this.handlers[n]=this.handlers[n]||[]).push(cb);return this;};Dropzone.prototype.emit=function(n){var a=[].slice.call(arguments,1);(this.handlers[n]||[]).forEach(function(cb){cb.apply(null,a);});};Dropzone.prototype.addFile=function(file){this.files.push(file);this.emit('addedfile',file);this.emit('error',file,'Uploads require the full Dropzone asset build.');};Dropzone.prototype.getAcceptedFiles=function(){return this.files.filter(function(f){return f.status==='success';});};Dropzone.prototype.destroy=function(){if(this.element)this.element.dropzone=null;this.handlers={};this.files=[];};w.Dropzone=Dropzone;})(window);
